1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	type QuoteResult = { premium: number };
15	
16	const itemPremium = (item: Item): number => {
17	  const base = BASE_PREMIUM[item.type];
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return base + firstInsuranceSurcharge;
20	};
21	
22	const quoteStep = (step: Step): QuoteResult => {
23	  const sum = step.items.reduce((acc, item) => acc + itemPremium(item), 0);
24	  return { premium: sum + PROCESSING_FEE };
25	};
26	
27	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
28	  results: scenario.steps.map(quoteStep),
29	});
